    public static void RegisterIcon(string name, string path)
    {
        Icons.Add(name, new Lazy<StreamGeometry>(StreamGeometry.Parse(path)));
    }

    public static PathIcon GetPathIcon(string key)
    {
        return Icons.TryGetValue(key, out var geometry)
            ? new PathIcon { Data = geometry.Value }
            : throw new ArgumentException("Icon not found", nameof(key));
    }

    public static FAPathIconSource GetPathIconSource(string key)
    {
        return Icons.TryGetValue(key, out var geometry)
            ? new FAPathIconSource { Data = geometry.Value }
            : throw new ArgumentException("Icon not found", nameof(key));
    }
}

public class PathIconExtension : MarkupExtension
{
    public string? Key { get; set; }

    public override object ProvideValue(IServiceProvider serviceProvider)
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(Key);
        return IconRegistry.GetPathIcon(Key);
    }
}

public class PathIconSourceExtension : MarkupExtension
{
    public string? Key { get; set; }

    public override object ProvideValue(IServiceProvider serviceProvider)
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(Key);
        return IconRegistry.GetPathIconSource(Key);
    }
}